var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"우습군요, 방해자.","JPN":"滑稽ですね、邪魔者。","ENG":"How amusing, Disturber.","TWN":"真是可笑，妨礙者。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"가아그셰블라는 신성 정보 집합체…….","JPN":"ガアグシェブラは神聖情報集合体……","ENG":"Gha'agsheblah is a Divinity collection of information...","TWN":"加格舍夫拉是神性情報集合體……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"고작 저희 중에 일부에 불과했던 당신이 저희를 탐식할 수 있다고 생각하나요?","JPN":"我々の一部に過ぎなかったあなたが、我々を貪食できると思いますか？","ENG":"Did you really think someone who was merely a fragment of us could devour us?","TWN":"不過只是我們的一部分，你以為能吞噬我們嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하하, 글쎄요?","JPN":"あはは、どうでしょう？","ENG":"Ahaha, who knows?","TWN":"哈哈哈，誰知道呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"혼자서는 조금 힘들지도 모르겠지만, 저는 혼자가 아닌 걸요?","JPN":"一人では少し心もとないかもしれませんけど……一人じゃありませんよ、私。","ENG":"On my own it might be a little difficult, but I am not alone, you see?","TWN":"一個人的話，或許有點勉強，但我可不是孤單一人。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"우리의 숙적이었던 기사님께서 함께하니까요!","JPN":"我々の宿敵だった騎士様が一緒ですから！","ENG":"After all, our former nemesis, my knight, is with me!","TWN":"因為曾是我們宿敵的騎士，要與我並肩作戰！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"끌어내려주지, 마이트너.","JPN":"引きずり下ろしてやろう、マイトナー。","ENG":"I'll drag you down, Meitner.","TWN":"我會把你拉下來，邁特納。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"심연의 밑바닥까지……!","JPN":"深淵の底まで……！","ENG":"All the way to the very bottom of the abyss...!","TWN":"直到深淵的最底層……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"큿, 예나 지금이나, 정말로 끈질긴 사슬이로군요……!","JPN":"くっ、昔も今も、なんてしつこい鎖……！","ENG":"Kgh, whether then or now, those chains really are tenacious...!","TWN":"嘖，無論過去還是現在，真是頑強的鎖鏈啊……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_1"},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈도 잘 알고 있을 텐데?","JPN":"貴様もわかっているだろう。","ENG":"You know it yourself, don't you?","TWN":"你自己也很清楚吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 사슬은 오직 네놈들을 묶어두기 위해 방패에서 벼려진 무장이라는 것을.","JPN":"この鎖は貴様らを縛りつけるためだけに盾から作られた武装。","ENG":"These chains are weapons forged from a shield solely to bind the likes of you.","TWN":"這條鎖鏈，正是為了束縛你們而自盾牌中鍛造的武裝。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"방패를 잃은 내가 이걸 쓸 수 있다는 건, 애초부터 이럴 운명이었다는 뜻이겠지!","JPN":"盾を失った俺がこれを扱えるということは、最初からこうなる運命だと決まっていたのだろう！","ENG":"The fact that I can wield them even after losing my shield means this was fate from the start!","TWN":"失去盾牌的我還能使用它，從一開始就注定會變成這樣吧！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그렇다면 수백 번이든, 수천 번이든 얽매여주마, 마이트너.","JPN":"ならば数百回でも、数千回でもその運命を受け入れてやろう。マイトナー。","ENG":"If that's the case, I'll bind you hundreds, even thousands of times, Meitner.","TWN":"既然如此，不管是幾百、幾千次，我都會纏住你們，邁特納。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈들의 그 잘난 신성 파편을 전부 소모─────","JPN":"貴様らのその神聖の破片とやらを全部消耗させ─────","ENG":"Until every last one of your precious Divinity Fragments is completely spent────","TWN":"把你們引以為傲的神性碎片全部消耗殆盡─────"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 기사를 먼저 처리하는 겁니다.","JPN":"エデル、先に騎士を仕留めるのです。","ENG":"Edel, deal with the Knight first.","TWN":"艾瑟兒，先處理騎士。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"봉인 사슬이 없다면, 당신이 방해자를 쓰러트리는 건 어렵지 않을 거예요.","JPN":"封印の鎖さえなければ、あなたが邪魔者を倒すことなど造作もないはずですわ。","ENG":"Without the Sealing Chains, defeating the Disturber won't be difficult for you.","TWN":"沒有封印鎖鏈的話，你要擊倒妨礙者並不困難。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"레지나, 제가 충고드렸을 텐데요?","JPN":"レジーナ、忠告したはずですよ？","ENG":"Regina, did I not warn you?","TWN":"蕾佳娜，我應該警告過你吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"시간을 얼리는 건, 신중하게 생각해야 한다고요?","JPN":"時間を凍結させるのは、慎重にやるべきだと。","ENG":"That freezing time is something you should consider very carefully.","TWN":"凍結時間這件事必須慎重考慮。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님……!?","JPN":"レジーナ様……！？","ENG":"Miss Regina...?!","TWN":"蕾佳娜大人……！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아무리 학회장이라고 해도, 당신은 결국 연약한 인간이랍니다.","JPN":"学会長といっても、あなたは所詮脆弱な人間。","ENG":"No matter if you are the President, you are still a fragile human in the end.","TWN":"就算你是學會長，終究也只是脆弱的人類。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"마왕의 위계를 이은 존재를 대적할 수 있을 리 없어요.","JPN":"魔王の位階を引き継いだ存在と張り合えるわけがありません。","ENG":"There is no way you can oppose one who inherited a Demon Lord's hierarchy.","TWN":"不可能與繼承魔王位階的存在抗衡。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그리고 이 싸움에서 어머니는 그런 당신을 지켜가면서 싸우고 있죠.","JPN":"そしてこの戦いでお母さんはそんなあなたを守りながら戦っています。","ENG":"And in this fight, Mother is protecting someone like you while she battles.","TWN":"而在這場戰鬥中，母親一邊保護你、一邊戰鬥。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"이런 상황에서 학회장이 시간을 멈추면…….","JPN":"こんな状況で学会長が時間を止めたら……","ENG":"In a situation like this, if the President freezes time...","TWN":"在這種情況下，若學會長停止時間……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"가아그셰블라 분체는 즉시 학회장을 노릴 거고, 본체는 이에 대응할 수밖에 없어요.","JPN":"ガアグシェブラの分体はすぐに学会長を狙うでしょうし、本体はそれに対応するしかありません。","ENG":"The Gha'agsheblah Fragment will immediately target the President, and she will have no choice but to respond.","TWN":"加格舍夫拉的分體會立刻以學會長為目標，而本體也不得不加以應對。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"마치 쳇바퀴가 돌아가듯, 상황은 계속해서 교착 상태에 빠질 겁니다.","JPN":"同じことが繰り返されるだけで、状況は膠着してしまうでしょう。","ENG":"Like a hamster wheel turning, the situation will continue to fall into a stalemate.","TWN":"局勢就會像轉動的齒輪持續陷入僵局。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"소감이 어떠신가요, 종교학부장님?","JPN":"感想はどうですか？　アビゲイル宗教学部長。","ENG":"How does it feel, Dean of Religion?","TWN":"你的感想如何呢，宗教學院院長？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"눈 앞에서 오랫동안 바라던 광경이 연출되고 있는데.","JPN":"目の前にずっと夢に描いていた光景が広がっていますが。","ENG":"A scene you have long desired is unfolding right before your eyes.","TWN":"你長久以來渴望的光景，正在眼前上演。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후후, 확실히 그렇네.","JPN":"ふふ、そうね。","ENG":"Fufu, that's certainly true.","TWN":"呵呵，確實如此。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이대로 소모전을 반복하면, 저 추악한 존재들이 모두 공멸해 버릴지도 모르겠지.","JPN":"このまま消耗戦が続けば、あの忌々しい存在たちが共倒れしてくれるかもね。","ENG":"If this war of attrition keeps repeating, those grotesque beings might all end up destroying each other.","TWN":"如果就這樣反覆進行消耗戰，那些醜陋的存在或許會全部同歸於盡吧。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"하지만 이렇게까지 서비스해주니까, 오히려 궁금한 걸?","JPN":"でも、さすがにここまでサービスされると逆に気になっちゃうわ。","ENG":"But since you're going this far, it actually makes me curious.","TWN":"不過都做到這種地步了，反而讓人好奇呢？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"각본가 양이 구상하고 있는 큰 그림이 말이야.","JPN":"脚本家のお嬢さんの計画が。","ENG":"About the bigger picture you're envisioning, scriptwriter.","TWN":"編劇小姐構想的大局。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"큰 그림이라고요?","JPN":"計画？","ENG":"The bigger picture?","TWN":"大局？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"샤레이드가 궤멸하고 학회와 교단이 대립하면, 각본가 양에게 남는 이득이 뭐지?","JPN":"シャレードが壊滅して学会と教団が対立したら、脚本家のお嬢さんは何を得られるのかしら？","ENG":"If Charade is annihilated and the Society and the faction come into conflict, what benefit is left for you?","TWN":"查雷德毀滅、學會與教團對立後，編劇小姐能得到什麼好處？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그저 세상이 불타는 게 즐거운 거야? 뭐, 그런 것도 나쁘지 않다고 생각해~","JPN":"世界が燃え上がるのが楽しいだけ？　ま、それも悪くないと思うけどね～","ENG":"Do you simply enjoy watching the world burn? Well, I suppose that wouldn't be so bad either.","TWN":"只是單純享受世界戰火四起的景象嗎？這我也不討厭就是了～"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"후후, 그럴리가요.","JPN":"ふふ、まさか。","ENG":"Haha, of course not.","TWN":"呵呵，怎麼可能。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"제가 바라는 건 하나뿐이랍니다.","JPN":"私が望むのは一つだけ。","ENG":"There is only one thing I desire.","TWN":"我所期望的，只有一件事。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"세계 평화예요.","JPN":"世界の平和です。","ENG":"World peace.","TWN":"世界和平。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아핫, 제법 뻔뻔한 면이 있네~","JPN":"あははっ、案外図々しいところもあるのね。","ENG":"Ahaha, you've got quite the audacity.","TWN":"啊哈，真是厚臉皮呢～"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"뒤에서 이런 각본을 꾸며놓고, 세계 평화를 바란다고?","JPN":"裏でこんな脚本を仕立てておいて、世界の平和？","ENG":"After plotting a script like this behind the scenes, you claim to want world peace?","TWN":"在背後策劃這種劇本，卻說想要世界和平？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"네, 저는 진심이랍니다.","JPN":"はい、私は本気です。","ENG":"Yes, I mean it sincerely.","TWN":"對，我是認真的。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"제가 아는 누군가가 말했거든요.","JPN":"私の知り合いがこう言いました。","ENG":"Someone I know once said this.","TWN":"我認識的一個人曾說過。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"세계를, 있는 그대로 온전히 지켜내는 것과 부숴서라도 지켜내는 것은 다르다고.","JPN":"世界を完全な形で守ることと、それを壊してでも守り通すことは違うと。","ENG":"There is a difference between protecting the world as it stands, and protecting it even at the cost of breaking it.","TWN":"「完整地守護世界」與「即使將其摧毀也要守護它」，兩者截然不同。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그러니까 당신 같은 악인과도 손을 잡을 수 있는 거예요.","JPN":"だからあなたのような悪人とも手を組めるのです。","ENG":"That's why I can join hands even with a villain like you.","TWN":"所以，我才能跟你這樣的惡人合作。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후후, 대놓고 악인이라니 섭섭한데?","JPN":"ふふ、面と向かって悪人って言われると傷つくわ。","ENG":"Fufu, calling me a villain outright is rather hurtful, you know?","TWN":"呵呵，張口就說我是惡人，真令人傷心呢？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"전조 현상이 시작된 이상, 그걸 막을 방법은 애초부터 없었어요.","JPN":"前兆現象が始まった以上、それを止める方法はありません。","ENG":"Once the omen phenomenon has begun, there was no way to stop it from the start.","TWN":"既然前兆現象已經開始，從一開始就沒有阻止的方法。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그렇다면, 이 현상을 역으로 이용하여 변수를 제거하는 거예요.","JPN":"ならば、この現象を逆に利用して変数を取り除くまで。","ENG":"In that case, we use the phenomenon itself to eliminate variables.","TWN":"既然如此，就反過來利用這個現象排除變數。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"머지않아 시작될 클리포트 게임에서 방해가 될 요소를 미리 배제해 두는 거죠.","JPN":"まもなく始まるクリフォトゲームで邪魔になる要素をあらかじめ排除するのです。","ENG":"We remove in advance anything that would interfere with the Qliphoth Game that will begin soon.","TWN":"也就是排除在不久後即將開始的逆卡巴拉遊戲內的妨礙因素。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그럼, 이제 슬슬 시간이 되었군요.","JPN":"では、そろそろ時間ですね。","ENG":"Then, it seems the time has finally come.","TWN":"那麼，時間差不多到了。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"이 교착 상태를 끝내기 위해, 우리가 준비한 마지막 카드를 꺼낼 시간이…….","JPN":"この膠着状態を終わらせるために、私たちが用意した最後の切り札を出す時間が……","ENG":"The time to bring this stalemate to an end by playing the final card we prepared...","TWN":"為了結束這場僵局，拿出我們準備好的最後一張牌吧……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"소용없습니다, 호수의 기사.","JPN":"無駄です、湖の騎士。","ENG":"It's useless, Knight of the Lake.","TWN":"沒有用的，湖水騎士。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"당신은 사도. 클리포트의 마왕보다는 격이 낮은 존재입니다.","JPN":"あなたは使徒。クリフォトの魔王より格下の存在です。","ENG":"You are an Apostle. A being of lower standing than the Demon Lords of Qliphoth,","TWN":"你是使徒，位階低於逆卡巴拉魔王。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그 사슬은 어디까지나 신성에 대적하는 무장. 신성이 없는 저에게는 의미가 없어요.","JPN":"その鎖はあくまで神聖に対抗する武装。神聖を持たない私には意味がありません。","ENG":"Those chains are merely a weapon meant to oppose Divinity. It has no meaning to someone without Divinity like me.","TWN":"那條鎖鏈終究只是對抗神性的武裝，對沒有神性的我毫無意義。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제 능력이라면, 얼마든지 파훼가 가능하죠.","JPN":"私の能力でいくらでも打ち破ることができますわ。","ENG":"With my ability, I can counter it as many times as I like.","TWN":"憑我的能力，破解它輕而易舉。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"과연 이성의 괴물이로군.","JPN":"さすがは理性の怪物。","ENG":"Truly, a monster of reason.","TWN":"果然是理性的怪物。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"고작 한 합을 주고받았을 뿐인데, 모든 것을 꿰뚫어 보듯 통찰하다니…….","JPN":"たった一戦交えただけで、すべてを見通すとは……","ENG":"We've only exchanged a single blow, yet you see through everything as if it were laid bare...","TWN":"不過只交手一回合，彷彿就洞悉全部看穿一切……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"허나, 그렇다고 해도 한계가 명확한 인간의 육체.","JPN":"だが、所詮は限界がある人間の肉体だ。","ENG":"Even so, the human body has clear limits.","TWN":"不過即便如此，人類的肉體仍有明確的極限。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니의 클리파로부터 힘을 끌어올 수 있는 사도와는 비교할 수 없겠지.","JPN":"お母さんのクリファから力を引き出せる使徒とは比べ物にならない。","ENG":"You cannot compare to an Apostle who can draw power from Mother's Qlipha.","TWN":"根本無法和能從母親的逆卡巴拉中汲取力量的使徒相比。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"단 한 번이라도 부상을 허용하면, 그것이 곧 네 최후가 될 거다, 맥크레디.","JPN":"一度でも傷を負えば、それが貴様の最期になるだろう。マクレディー。","ENG":"Allow even a single wound, and that will be your end, MacCready.","TWN":"那怕只要讓我受傷一次，那就是你的末日，麥克蕾蒂。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그렇다면 시험해 보죠, 호수의 기사.","JPN":"ならば試してみましょう、湖の騎士。","ENG":"Then let us put it to the test, Knight of the Lake.","TWN":"那就試試看吧，湖水騎士。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"맥크레디 가문과 가아그셰블라의 사도. 둘 중 누가 더 호수의 가호를 받고 있는지.","JPN":"マクレディー家とガアグシェブラの使徒。湖の加護をより受けているのはどちらか。","ENG":"Between the MacCready bloodline and the Apostle of Gha'agsheblah. Let us see who truly bears the Lake's blessing.","TWN":"看看麥克蕾蒂家族與加格舍夫拉的使徒，究竟誰會得到更多湖水加護。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아하하! 저희 꼴이 참 웃기지 않나요, 어머니?","JPN":"あはは！　この状況、滑稽だと思いませんか、お母さん？","ENG":"Ahahaha! Don't we look ridiculous, Mother?","TWN":"啊哈哈！我們現在的模樣不是很可笑嗎，母親？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"서로가 서로의 살점을 뜯어먹고 있잖아요. 이래서야 도돌이표라고요?","JPN":"互いの肉を貪り合っているだけで、何も進んでないじゃないですか。","ENG":"Tearing into each other's flesh like this. Is this what you call going in circles?","TWN":"彼此啃食彼此的血肉，所以才說是無限循環啊？"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"하지만 오랜만에 맛보는 어머니의 살결은 참으로 감미롭네요.","JPN":"でも、久しぶりに味わうお母さんの肌は実に甘美ですね。","ENG":"Still, tasting Mother's flesh again after so long is exquisitely sweet.","TWN":"不過，好久沒品嘗母親的肌膚，真是甘美呢。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그거 아쉽게 됐네요, 방해자.","JPN":"残念です、邪魔者。","ENG":"That's unfortunate, Disturber.","TWN":"真遺憾，妨礙者。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저와 대등한 눈높이에 서고 싶다면, 더 열심히 파편을 모으는 편이 좋았을 텐데.","JPN":"私と対等になりたいのなら、もっと破片集めに精を出していればよかったのに。","ENG":"If you wanted to stand at eye level with me, you should have gathered far more Fragments.","TWN":"你要是想站在與我對等的高度，應該更早就要努力收集碎片啊。"},"stage":{"bg":"PRYDWEN_02","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"큭……!?","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"嘖……！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"사실, 저희는 남 몰래 응원하고 있답니다, 방해자.","JPN":"実は密かに応援しているのです、邪魔者。","ENG":"In truth, we've been secretly cheering for you, Disturber.","TWN":"其實我們可是暗中為你加油呢，妨礙者。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"당신이 수거한 가아그셰블라의 파편은 어차피 돌고돌아 전부 저희 것이 될 테니까요.","JPN":"あなたが回収したガアグシェブラの破片はいずれずべて、我々のものになるでしょうから。","ENG":"After all, every Fragment of Gha'agsheblah you collected will eventually return to us.","TWN":"反正你回收的加格舍夫拉碎片，繞了一圈後還是都會成為我們的東西。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"하하핫, 그래서요?","JPN":"あははっ、それで？","ENG":"Hahaha, so what?","TWN":"哈哈，那又如何？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"과연 그렇게 되면, 감정을 얼려버려 인형이 되어버린 지금의 레지나가 기뻐할까요?","JPN":"そうなったら、感情を凍らせて人形になった今のレジーナは喜ぶでしょうか？","ENG":"And if that happens, do you think the current Regina, who froze her emotions and became a doll, would be happy?","TWN":"如果真變成那樣，現在這個情感被凍結、成了人偶的蕾佳娜，會感到高興嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"방해자…! 또 나의 레지나 님을 모욕하다니……!","JPN":"邪魔者……！　また我々のレジーナ様を侮辱するなんて……！","ENG":"Disturber...! How dare you mock our Regina again...?!","TWN":"妨礙者……！竟然又侮辱我的蕾佳娜大人……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이래서 그저 <color=#ff3636>탐식</color>할 뿐인 어머니는 <color=#ff3636>미식</color>을 이해하지 못하는 거예요.","JPN":"だからただ<color=#ff3636>貪食</color>するだけのお母さんは<color=#ff3636>美食</color>を理解できないんです。","ENG":"That's why a mother who only knows to <color=#ff3636>devour</color> can never understand <color=#ff3636>taste</color>.","TWN":"所以我才說，只會<color=#ff3636>吞噬</color>的母親，永遠不懂<color=#ff3636>美食</color>啊。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"인간의 그 절절한 감정이야말로, 어떤 정보에서도 맛볼 수 없는 별미 중의 별미인데.","JPN":"人間を人間たらしめるあの切ない感情こそ、どの情報からも味わうことのできない珍味なのに。","ENG":"Those desperate human emotions are delicacies no information could ever replicate.","TWN":"人類那種刻骨銘心的情感，才是無法在任何情報品嘗到的極品珍饈。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저런 무감정한 레지나를 탐식해 봤자, 어차피 아무 맛도 느껴지지 않을 거라고요?","JPN":"あんな無感情なレジーナを貪食したところで、何の味もしませんよ？","ENG":"Devouring an emotionless Regina would leave you tasting nothing at all, you know?","TWN":"你去吞噬那種沒感情的蕾佳娜看看，反正什麼味道都嚐不到吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"듣자 듣자, 하니 대화 수준이 너무 저열해서 더는 못 들어주겠군요.","JPN":"会話の内容が低レベルすぎて、聞くに堪えませんわね。","ENG":"I've listened long enough. This conversation has sunk to a level I can no longer tolerate.","TWN":"你們的對話實在太沒水準，我再也聽不下去了。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어라, 이 목소리는……?","JPN":"あら、この声は……？","ENG":"Huh? That voice...","TWN":"咦，這個聲音是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"지금이에요, 버넷……!","JPN":"今です、バーネット……！","ENG":"Now, Burnett...!","TWN":"就是現在，伯內特……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"알고 있어! 봉인 사슬 전개!","JPN":"わかってるって！　封印の鎖、展開！","ENG":"I know! Deploying Sealing Chains!","TWN":"我知道！封印鎖鏈展開！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"이 사슬은……?","JPN":"この鎖は……？","ENG":"Those chains...","TWN":"這條鎖鏈是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈인가! 애송이 주제에 가소롭군!","JPN":"貴様か！　身の程も弁えず、小癪な真似を！","ENG":"Is that you? How laughable, you whelp!","TWN":"是你嗎！區區小鬼，真可笑！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"겨우 이 따위 사슬로 어머니를 구속할 수 있을 거라고 생각했나……!","JPN":"これしきの鎖でお母さんを拘束できるとでも思ったか……！","ENG":"Did you really think chains like these could bind Mother...!","TWN":"你以為憑這種鎖鏈就能束縛母親嗎……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"아니, 봉인 사슬로 저 아이를 노리면 기사님이 곧장 달려올 거라고 생각했거든.","JPN":"いや、封印の鎖であの子を狙えば、騎士様がすぐ駆けつけてくるだろうと思ってな。","ENG":"No. I figured if I aimed the Sealing Chains at that girl, you'd come charging in right away.","TWN":"不，我只是在想，如果用封印鎖鏈瞄準那孩子，騎士一定會立刻衝過來。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_1"},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"바로 지금처럼.","JPN":"まさに今みたいに。","ENG":"Just like now.","TWN":"就像現在這樣。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"뭐라고? 설마……?","JPN":"何？　まさか……？","ENG":"What? You don't mean...?","TWN":"什麼？難道……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"지금이야, 루키! 백업은 나한테 맡겨……!","JPN":"今だ、ルーキー！　バックアップは俺に任せとけ……！","ENG":"Now's the time, rookie! Leave the backup to me...!","TWN":"就是現在，菜鳥！支援交給我……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"크흑……!?","JPN":"くっ……！？","ENG":"Kuh...?!","TWN":"咳……！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"신성이 담긴 참격이라고?","JPN":"神聖が込められた斬撃だと？","ENG":"A strike imbued with Divinity?","TWN":"帶有神性的斬擊？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"설마, 가아그셰블라의 새로운 파편인가……?","JPN":"まさか、新しいガアグシェブラの破片か……？","ENG":"Don't tell me... a new Gha'agsheblah Fragment...?","TWN":"難道是加格舍夫拉的新碎片……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"기사님! 괜찮으세요……?","JPN":"騎士様！　大丈夫ですか……？","ENG":"My knight! Are you all right...?","TWN":"騎士！你沒事吧……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이 정도는 문제없습니다, 나의 어머니시여.","JPN":"この程度何でもありません、お母さん。","ENG":"This is nothing to worry about, Mother.","TWN":"這點程度不成問題，我的母親。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_NULL","text":{"KOREA":"어, 어땠어? 토토……?","JPN":"ど、どうだった？　トト……？","ENG":"H-how was it, Toto...?","TWN":"呃、怎麼樣？托托……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L12_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 너무해! 그렇지만…! 나, 칼을 휘둘러본 게 처음인걸……!","JPN":"え？　ひどい！　だって……！　私、剣を振るのは初めてなんだよ……！","ENG":"What? That's harsh! But still...! It was my first time swinging a sword...!","TWN":"什麼？太過分了！可是……！我、還是第一次揮刀……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L15_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"아오! 이 멍청한 년! 진짜 답답하게 구네……!","JPN":"ああもう！　このバカ女！　何をもたもたしてやがる……！","ENG":"Ugh! You stupid wench! You're seriously frustrating!","TWN":"啊啊！你這個蠢女人！我真的快被你氣死了……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"그거 하나 제대로 못 끝장 내놓고, 뭐? 칼을 휘둘러보는 게 처음이야?","JPN":"あんなもんも仕留めきれなかったくせに、何だ？　剣を振るのが初めて？","ENG":"You couldn't even finish off one target, and what? This is your first time swinging a sword?","TWN":"連這種東西都解決不了，什麼？還敢說自己第一次揮刀？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"염병하네! 그럼, 그동안 나한테 시켰던 건 뭐야? 내가 등긁개였냐? 파리채였어?","JPN":"ふざけてんじゃねぇ！　じゃあ今まで俺にやらせてたのは何だ？　俺は孫の手か？　ハエたたきか？","ENG":"Oh, give me a break! Then what was all that stuff you made me do before, huh? Was I a back scratcher? A flyswatter?","TWN":"到底在發什麼神經！那之前一直叫我做的事是什麼？我是不求人還是蒼蠅拍嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"하여간 쓸데없이 가슴만 커가지고. 머리에 든 게 없냐, 넌?","JPN":"無駄に胸だけデカくてさ、脳みそに何詰まってんだよお前は！","ENG":"Honestly, all bust and no brains. Is your head completely empty?","TWN":"真是的，你只有胸部長那麼大，腦袋裡卻什麼都沒有嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈啊……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"아앙? 웬 한숨이야, 놈팽이? 뒈지고 싶어?","JPN":"ああん？　何ため息ついてんだ？　このチンピラが！　死にてぇのか？","ENG":"Huh? What's with the sigh, scumbag? You wanna die?","TWN":"啊？嘆什麼氣啊，廢物？想死嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"다시 봐도 적응이 안 되는군요, 저건…….","JPN":"何度見ても慣れませんわね、あれは……","ENG":"No matter how many times I see it, I can't get used to that...","TWN":"不管看多少次還是無法習慣啊，那個……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"아아~ 잘 지냈어? 가아그셰블라 패밀리 여러분?","JPN":"ああ～元気にしてたか？　ガアグシェブラファミリーの皆さん？","ENG":"Aah, been well, everyone from the Gha'agsheblah family?","TWN":"啊啊～過得好嗎？加格舍夫拉家族的各位？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L30_1","type":"dialog","speaker":"SWORD_PRYDWEN_NULL_QM","text":{"KOREA":"나 없이도 다들 행복해 보여서 아주 배알이 꼴린다고? 나는 후레자식이다 이거지?","JPN":"俺がいなくても幸せそうで胸糞悪いな。俺はもう除け者扱いか？","ENG":"You all look so happy without me and it really makes my blood boil. So I'm the bastard here, huh?","TWN":"看你們就算沒有我也過得很幸福，真讓人火大呢？我真是個不肖子吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_PRYDWEN_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"당신은, 설마……?","JPN":"あなたは、まさか……？","ENG":"Are you the...?","TWN":"你該不會是……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"추적자, <color=#ffd34c>틴달로스의 개</color>로군요.","JPN":"追跡者、<color=#ffd34c>ティンダロスの犬</color>ですね。","ENG":"It's the Chaser. The <color=#ffd34c>Hound of Tindalos</color>.","TWN":"追擊者，<color=#ffd34c>廷達羅斯獵犬</color>。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"귀찮게 무슨 본명이야. 그냥 토토라고 불러.","JPN":"フルネームは面倒くさいからトトでいい。","ENG":"What's with the fancy real name? Just call me Toto.","TWN":"幹嘛這麼麻煩說我本名，叫我托托就好。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그쪽을 엄마라고 부르면 돼? 그럼, 이쪽은 누님이신가? ","JPN":"そっちが母さんでいいか？　じゃ、こっちは姉さんかな？ ","ENG":"So I call you Mom? Then would this one be Sis?","TWN":"我可以叫那位媽媽嗎？那這邊就是姐姐囉？ "},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"이상하다? 근데 왜 누님이 많이 어린 것 같냐?","JPN":"あれっ？　姉さんにしては幼なすぎないか？","ENG":"Huh, that's weird. Why does she look so young?","TWN":"真奇怪？不過姐姐是不是看起來有點太年輕了？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 아무렴 어때~","JPN":"ま、どうでもいいや。","ENG":"Ah well, who cares!","TWN":"算了～"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그동안 굶주렸던 만큼, 잔뜩 먹어 치울 생각이거든?","JPN":"今まで飢えてた分、存分に食らい尽くすつもりだから、そこんとこよろしく。","ENG":"I've been starving for ages, so I'm planning to eat my fill.","TWN":"既然餓了那麼久，當然要大吃特吃囉？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L42_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 지금부터 <color=#ff3636>폭식</color> 타임이라구……!","JPN":"さあ、<color=#ff3636>暴食</color>タイムの始まりだ……！","ENG":"All right, it's <color=#ff3636>binge</color> time...!","TWN":"那麼，現在開始就是<color=#ff3636>暴食</color>時間啦……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};